/* Cover - most common for images */
.image {
  width: 100%;
  height: 300px;
  object-fit: cover;
}

/* Contain - shows entire image */
.product-image {
  width: 200px;
  height: 200px;
  object-fit: contain;
}

/* Fill - stretches (avoid unless intentional) */
.banner {
  width: 100%;
  height: 400px;
  object-fit: fill;
}

/* None - original size, may overflow */n  .avatar {
  width: 100px;
  height: 100px;
  object-fit: none;
  object-position: center;
}

/* Scale-down - intelligently chooses smallest */
.responsive-img {
  width: 100%;
  height: auto;
  object-fit: scale-down;
}

/* Default position: center */
.image {
  object-fit: cover;
  object-position: center; /* default */
}

/* Custom positioning (similar to background-position) */
.image {
  object-fit: cover;
  object-position: top left;
}

/* Pixel values */
.image {
  object-fit: cover;
  object-position: 20px 10px;
}

/* Percentage values */
.image {
  object-fit: cover;
  object-position: 25% 75%;
}

/* Edge keywords */
.image {
  object-position: right top;
  object-position: left bottom;
  object-position: center right;
}

/* Combined values */
.image {
  object-position: 10% 20px;
  object-position: right 10px top 20px;
}

/* 1. Responsive Hero Image */
.hero {
  width: 100%;
  height: 60vh;
  overflow: hidden;
}

.hero img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  object-position: center 30%; /* Focus on specific area */
}

/* 2. Product Gallery (uniform thumbnails) */
.product-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
  gap: 20px;
}

.product-card img {
  width: 100%;
  height: 200px;
  object-fit: contain;
  background: #f5f5f5;
}

/* 3. Avatar / Profile Pictures */
.avatar {
  width: 80px;
  height: 80px;
  border-radius: 50%;
  overflow: hidden;
}

.avatar img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  object-position: center;
}

/* 4. Card Images */
.card {
  width: 300px;
  border-radius: 8px;
  overflow: hidden;
  box-shadow: 0 2px 8px rgba(0,0,0,0.1);
}

.card img {
  width: 100%;
  height: 200px;
  object-fit: cover;
  transition: transform 0.3s ease;
}

.card:hover img {
  transform: scale(1.05);
}

/* 5. Logo Container (different aspect ratios) */
.logo-container {
  width: 150px;
  height: 80px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.logo-container img {
  max-width: 100%;
  max-height: 100%;
  object-fit: contain;
}

/* 6. Background-style image (alternative to background-image) */
.bg-image {
  position: relative;
  height: 400px;
  overflow: hidden;
}

.bg-image img {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
  z-index: -1;
}

/* Focus on specific face in group photo */
.team-photo {
  width: 100%;
  height: 300px;
  object-fit: cover;
  object-position: 65% 40%;
}

/* Responsive object-position */
@media (max-width: 768px) {
  .hero img {
    object-position: 70% center; /* Different focus on mobile */
  }
}

/* Animated object-position */
.slideshow img {
  object-fit: cover;
  object-position: 0% center;
  transition: object-position 1s ease;
}

.slideshow img:hover {
  object-position: 100% center;
}

/* Using CSS variables */
:root {
  --focus-x: 50%;
  --focus-y: 50%;
}

.dynamic-image {
  object-fit: cover;
  object-position: var(--focus-x) var(--focus-y);
}

/* With JavaScript control */
/* Can update variables dynamically based on user interaction */

/* Video background */
.video-background {
  position: relative;
  width: 100%;
  height: 100vh;
  overflow: hidden;
}

.video-background video {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
  z-index: -1;
}

/* Responsive video container */
.video-container {
  width: 100%;
  max-width: 800px;
  margin: 0 auto;
}

.video-container video {
  width: 100%;
  height: auto;
  object-fit: contain;
}

/* Thumbnail preview */
.video-thumbnail {
  width: 320px;
  height: 180px; /* 16:9 aspect ratio */
  object-fit: cover;
  cursor: pointer;
}

/* Feature detection */
@supports (object-fit: cover) {
  .image {
    object-fit: cover;
  }
}

/* Fallback for older browsers */
.image-container {
  width: 300px;
  height: 200px;
  overflow: hidden;
  position: relative;
}

.image-container img {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  min-width: 100%;
  min-height: 100%;
  max-width: none;
}

/* Modern approach with object-fit */
.image {
  width: 100%;
  height: 200px;
  object-fit: cover;
}

/* Using background-image as fallback */
.image-fallback {
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;
}

.image-fallback img {
  opacity: 0; /* Hide img, show background */
}

/* 1. Social Media Feed (uniform post images) */
.post-image {
  width: 100%;
  height: 400px;
  object-fit: cover;
}

/* 2. E-commerce Product Grid */
.product-image {
  width: 100%;
  height: 250px;
  object-fit: contain;
  background: white;
  padding: 20px;
}

/* 3. User Gallery */
.gallery-item {
  aspect-ratio: 1 / 1; /* Square */
  overflow: hidden;
}

.gallery-item img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: transform 0.3s;
}

.gallery-item:hover img {
  transform: scale(1.1);
}

/* 4. Before/After Images */
.comparison {
  display: flex;
  gap: 20px;
}

.comparison img {
  width: 50%;
  height: 300px;
  object-fit: cover;
  object-position: center;
}

/* 5. Mood Board / Pinterest Style */
.masonry-grid img {
  width: 100%;
  height: auto;
  object-fit: cover;
  margin-bottom: 20px;
  border-radius: 8px;
}

/* 6. Email Signature Logo */
.signature-logo {
  width: 120px;
  height: 40px;
  object-fit: contain;
  object-position: left center;
}

/* Modern approach: combining aspect-ratio with object-fit */
.responsive-media {
  aspect-ratio: 16 / 9;
  width: 100%;
}

.responsive-media img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

/* Different aspect ratios for different devices */
.hero-image {
  aspect-ratio: 16 / 9;
  width: 100%;
}

@media (min-width: 768px) {
  .hero-image {
    aspect-ratio: 21 / 9;
  }
}

/* Fixed aspect ratio grid */
.grid-square {
  aspect-ratio: 1 / 1;
  overflow: hidden;
}

.grid-square img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

/* Portrait orientation */
.portrait-container {
  aspect-ratio: 3 / 4;
}

/* Landscape orientation */
.landscape-container {
  aspect-ratio: 4 / 3;
}

